// Parse LiteLLM response + build PR comment
const prData = $('Build review prompt').first().json;
const llmResponse = $input.first().json;

let review;
try {
  const content = llmResponse.choices?.[0]?.message?.content || '';
  // Extract JSON from response (handle markdown code blocks)
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  review = JSON.parse(jsonMatch ? jsonMatch[0] : content);
} catch (e) {
  review = {
    status: 'UNKNOWN',
    summary: 'Failed to parse LLM response',
    critical: [],
    warnings: [],
    suggestions: []
  };
}

const statusEmoji = review.status === 'PASS' ? '✅' : review.status === 'FAIL' ? '❌' : '⚠️';
const model = llmResponse.model || 'unknown';
const tokens = (llmResponse.usage?.total_tokens || 0);

// Build GitHub PR comment in Markdown
const lines = [
  `## ${statusEmoji} Auto-Review VPAI — ${review.status}`,
  '',
  `**Résumé**: ${review.summary || 'N/A'}`,
  `**Fichiers analysés**: ${prData.reviewFileCount} | **Modèle**: \`${model}\` | **Tokens**: ${tokens}`,
  ''
];

if (review.critical && review.critical.length > 0) {
  lines.push('### 🔴 Problèmes critiques (bloquants)');
  review.critical.forEach(c => lines.push(`- ${c}`));
  lines.push('');
}

if (review.warnings && review.warnings.length > 0) {
  lines.push('### 🟡 Avertissements');
  review.warnings.forEach(w => lines.push(`- ${w}`));
  lines.push('');
}

if (review.suggestions && review.suggestions.length > 0) {
  lines.push('### 💡 Suggestions');
  review.suggestions.forEach(s => lines.push(`- ${s}`));
  lines.push('');
}

lines.push('---');
lines.push('*Review automatique par [Javisi Auto-Review](https://github.com/Mobutoo/VPAI) via LiteLLM*');

const comment = lines.join('\n');
const isPass = review.status === 'PASS';

return [{ json: {
  ...prData,
  review_status: review.status,
  review_pass: isPass,
  review_comment: comment,
  review_model: model,
  review_tokens: tokens,
  critical_count: (review.critical || []).length,
  warning_count: (review.warnings || []).length
}}];

